    "compodocArgs": ["-p", "packages/ngx-smart-components/tsconfig.lib.json", "-e", "json", "-d", "packages/ngx-smart-components"]
  }
},
"build-storybook": {
  "outputs": ["{options.outputDir}", "{projectRoot}/documentation.json"],
  "options": {
    "outputDir": "dist/storybook/ngx-smart-components",
    "configDir": "packages/ngx-smart-components/.storybook",
    "browserTarget": "ngx-smart-components:build-storybook",
    "compodoc": true,
    "compodocArgs": ["-p", "packages/ngx-smart-components/tsconfig.lib.json", "-e", "json", "-d", "packages/ngx-smart-components"]
  }
}
```

`ngx-smart-components.ts` (final):
